#include <climits>\n#include <cstdint>\n#include <iostream>\n#include <queue>\n#include <vector>\n\n#define INF (UINT64_MAX)\n\nclass Graph {\n public:\n  Graph(size_t n, const std::vector<std::vector<size_t>>& edges) {\n    n_ = n;\n    table_.resize(n_);\n    Build(edges);\n  }\n\n  size_t WayLength(size_t a, size_t b) {\n    a--;\n    b--;\n    std::vector<std::queue<size_t>> qs(n_ * k_ + 1);\n    std::vector<size_t> dist(n_, INF);\n    std::vector<bool> used(n_, false);\n    qs[0].push(a);\n    dist[a] = 0;\n    for (size_t d = 0; d <= n_ * k_; d++) {\n      while (!qs[d].empty()) {\n        size_t v = qs[d].front();\n        qs[d].pop();\n        if (used[v] || dist[v] > d) {\n          continue;\n        }\n        used[v] = true;\n        const std::vector<std::pair<size_t, size_t>>& children = table_[v];\n        for (const std::pair<size_t, size_t>& ch_pair : children) {\n          auto ch_vertex = ch_pair.first;\n          auto ch_weight = ch_pair.second;\n          if (dist[ch_vertex] > dist[v] + ch_weight) {\n            dist[ch_vertex] = dist[v] + ch_weight;\n            qs[dist[ch_vertex]].push(ch_vertex);\n          }\n        }\n      }\n    }\n    return dist[b];\n  }\n\n private:\n  void Build(const std::vector<std::vector<size_t>>& edges) {\n    for (const std::vector<size_t>& edge : edges) {\n      k_ = std::max(k_, edge[2]);\n      table_[edge[0] - 1].emplace_back(edge[1] - 1, edge[2]);\n    }\n  }\n\n  std::vector<std::vector<std::pair<size_t, size_t>>> table_;\n  size_t k_ = 0;\n  size_t n_ = 0;\n};\n\nint main() {\n  size_t n = 0;\n  size_t m = 0;\n  size_t a = 0;\n  size_t b = 0;\n  std::cin >> n >> m >> a >> b;\n\n  std::vector<std::vector<size_t>> edges(m);\n  for (std::vector<size_t>& edge : edges) {\n    edge.resize(3);\n    std::cin >> edge[0] >> edge[1] >> edge[2];\n  }\n  Graph g(n, edges);\n  auto answer = g.WayLength(a, b);\n  if (answer == INF) {\n    std::cout << -1 << std::endl;\n  } else {\n    std::cout << answer << std::endl;\n  }\n  return 0;\n}\n